action.old_str:
llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  auto& irb = *mCurIrb;
  auto* callee = self(obj->head);

  std::vector<llvm::Value*> args;
  for (auto* arg : obj->args) {
    args.push_back(self(arg));
  }

  return irb.CreateCall(
    llvm::cast<llvm::FunctionType>(callee->getType()->getPointerElementType()),
    callee, args);
}

action.new_str:
llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  if (!obj || !obj->head) {
    return nullptr;
  }
  auto& irb = *mCurIrb;
  auto* callee = self(obj->head);

  if (!callee) {
    return nullptr;
  }

  std::vector<llvm::Value*> args;
  for (auto* arg : obj->args) {
    auto* a = self(arg);
    if (a) {
      args.push_back(a);
    }
  }

  // Get function type from module
  auto* func = mMod.getFunction(obj->head->name);
  if (!func) {
    return nullptr;
  }

  return irb.CreateCall(func, args);
}

